What is printed in C++17?

```cpp
#include <iostream>
#include <type_traits>
template <typename T>
void show(T x) {
  if constexpr (std::is_integral_v<T>)
    std::cout << x + 1;
  else
    std::cout << x;
}
int main() {
  show(41);
}
```

